"use strict";(self.webpackChunkbcsd_blog=self.webpackChunkbcsd_blog||[]).push([[6465],{3416:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"/posts/introduce-DA-2025","metadata":{"permalink":"/data-analyst/posts/introduce-DA-2025","source":"@site/@dataAnalyst/posts/introduce-DA-2025.mdx","title":"BCSD \uac00\uc774\ub4dc: DA","description":"DA \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","date":"2025-05-05T00:00:00.000Z","tags":[{"label":"DA","permalink":"/data-analyst/tags/da"},{"label":"\ud2b8\ub799 \uc18c\uac1c","permalink":"/data-analyst/tags/\ud2b8\ub799-\uc18c\uac1c"}],"readingTime":5.7,"hasTruncateMarker":true,"authors":[{"name":"\uc774\uc0c1\ud654","url":"https://github.com/LeeSang-hwa","email":"tkdghk4110@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/133574367?v=4","key":"LeeSang-hwa"}],"frontMatter":{"date":"2025-05-05T00:00:00.000Z","authors":"LeeSang-hwa","title":"BCSD \uac00\uc774\ub4dc: DA","description":"DA \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!","keywords":["DA","\ud2b8\ub799 \uc18c\uac1c"],"tags":["DA","\ud2b8\ub799 \uc18c\uac1c"]},"unlisted":false},"content":"DA \ud2b8\ub799\uc744 \uc18c\uac1c\ud569\ub2c8\ub2e4!\\n\\n{/* truncate */}\\n\\n# **BCSD DA Track Introduce**\\n\\n# **: \ub370\uc774\ud130 \ubd84\uc11d\uac00\uac00 \ub418\ub294 \uc5ec\uc815**\\n\\n\ub370\uc774\ud130 \ubd84\uc11d\uac00(DA) \ud2b8\ub799\uc5d0 \uc624\uc2e0 \uc5ec\ub7ec\ubd84\uc744 \ud658\uc601\ud569\ub2c8\ub2e4!\\n\\n\uc774 \ud2b8\ub799\uc740 \ub370\uc774\ud130 \uae30\ubc18 \uc0ac\uace0\ub97c \ubc14\ud0d5\uc73c\ub85c, \ub2e4\uc591\ud55c \ube44\uc988\ub2c8\uc2a4 \ubb38\uc81c\ub97c \ud574\uacb0\ud560 \uc218 \uc788\ub294 **\uc2e4\uc804 \uc5ed\ub7c9**\uc744 \uae30\ub974\ub294 \uacfc\uc815\uc785\ub2c8\ub2e4.\\n\\n**Python\uacfc SQL \uae30\ucd08\ubd80\ud130 A/B \ud14c\uc2a4\ud2b8, \ub9ac\ud150\uc158 \ubd84\uc11d\uae4c\uc9c0** \uc2e4\uc81c \ub370\uc774\ud130 \ubd84\uc11d\uac00\uc758 \uc5c5\ubb34 \ud750\ub984\uc5d0 \ub9de\ucdb0 \ucee4\ub9ac\ud058\ub7fc\uc774 \uad6c\uc131\ub418\uc5b4 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## **\ud83e\udd14 \ub370\uc774\ud130 \ubd84\uc11d\uc774\ub780 \ubb34\uc5c7\uc778\uac00\uc694?**\\n\\n\ub370\uc774\ud130 \ubd84\uc11d\uc774\ub780 **\uc22b\uc790\uc640 \uae30\ub85d\uc73c\ub85c \ub0a8\uc544\uc788\ub294 \ub2e4\uc591\ud55c \ub370\uc774\ud130\ub97c \uc218\uc9d1\xb7\uc815\ub9ac\ud558\uace0, \uadf8 \uc18d\uc5d0\uc11c \uc758\ubbf8\ub97c \ucc3e\uc544\ub0b4\uc5b4 \uc2e4\uc81c \ubb38\uc81c \ud574\uacb0\uc5d0 \ud65c\uc6a9\ud558\ub294 \uc77c**\uc744 \ub9d0\ud569\ub2c8\ub2e4.\\n\\n\uc544\ub798\uc640 \uac19\uc740 \uc608\uc2dc\ub85c \uc774\ud574\ud574\ubcfc \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n- **\uc608\uc2dc 1: \uc0ac\uc6a9\uc790 \ud589\ub3d9 \ubd84\uc11d**\\n    \\n    \uc1fc\ud551\ubab0\uc5d0\uc11c \uc5b4\ub5a4 \uc0c1\ud488\uc774 \uac00\uc7a5 \ub9ce\uc774 \ud314\ub9ac\ub294\uc9c0, \uc0ac\ub78c\ub4e4\uc774 \uc5b4\ub5a4 \uacbd\ub85c\ub85c \ub4e4\uc5b4\uc640\uc11c \uad6c\ub9e4\uae4c\uc9c0 \uc774\uc5b4\uc9c0\ub294\uc9c0 \ub370\uc774\ud130\ub97c \ubd84\uc11d\ud574\\n    \\n    \\"\uc5b4\ub5a4 \uc0c1\ud488\uc744 \uba54\uc778\uc5d0 \ubc30\uce58\ud558\uba74 \uc88b\uc744\uc9c0\\" \ub610\ub294 \\"\uc5b4\ub5a4 \ud398\uc774\uc9c0\uc5d0\uc11c \uc774\ud0c8\uc774 \ub9ce\uc740\uc9c0\\"\ub97c \ud30c\uc545\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n- **\uc608\uc2dc 2: \uc11c\ube44\uc2a4 \uac1c\uc120**\\n    \\n    \uc571\uc5d0\uc11c \ud2b9\uc815 \uae30\ub2a5\uc744 \ucd94\uac00\ud588\uc744 \ub54c \uc0ac\uc6a9\uc790\uac00 \ub354 \uc624\ub798 \uba38\ubb34\ub294\uc9c0, \uc774\ud0c8\ub960\uc774 \uc904\uc5b4\ub4dc\ub294\uc9c0\\n    \\n    \ub370\uc774\ud130\ub97c \ubc14\ud0d5\uc73c\ub85c \uae30\ub2a5 \uac1c\uc120\uc758 \ud6a8\uacfc\ub97c \uac1d\uad00\uc801\uc73c\ub85c \uce21\uc815\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n- **\uc608\uc2dc 3: A/B \ud14c\uc2a4\ud2b8**\\n    \\n    \ubc84\ud2bc \uc0c9\uc0c1\uc744 \ubc14\uafe8\uc744 \ub54c \ud074\ub9ad\ub960\uc774 \ub354 \ub192\uc544\uc9c0\ub294\uc9c0, \ub450 \uac00\uc9c0 \ubc84\uc804\uc744 \uc0ac\uc6a9\uc790 \uc9d1\ub2e8\uc5d0 \ub098\ub220 \uc2e4\ud5d8\ud558\uace0\\n    \\n    \ud1b5\uacc4\uc801\uc73c\ub85c \uc758\ubbf8 \uc788\ub294 \ucc28\uc774\uac00 \uc788\ub294\uc9c0 \uac80\uc99d\ud569\ub2c8\ub2e4.\\n    \\n\\n\uc774\ucc98\ub7fc \ub370\uc774\ud130 \ubd84\uc11d\uac00\ub294 **\uc22b\uc790\uc640 \uae30\ub85d \uc18d\uc5d0\uc11c \uc778\uc0ac\uc774\ud2b8\ub97c \ucc3e\uc544\ub0b4\uace0, \ube44\uc988\ub2c8\uc2a4\uc640 \uc11c\ube44\uc2a4\uc758 \ubc29\ud5a5\uc131\uc744 \ub370\uc774\ud130\ub85c \ub4b7\ubc1b\uce68\ud558\ub294 \uc5ed\ud560**\uc744 \ud558\uac8c \ub429\ub2c8\ub2e4.\\n\\n---\\n\\n## **\ud83d\udccc \ud2b8\ub799 \uac1c\uc694**\\n\\n- **\ub370\uc774\ud130 \uc218\uc9d1\uacfc \uc804\ucc98\ub9ac \uc5ed\ub7c9 \uac15\ud654**\\n    \\n    Python\uacfc SQL\uc744 \ud65c\uc6a9\ud574 \ub370\uc774\ud130 \ubd84\uc11d\uc5d0 \ud544\uc694\ud55c \uae30\ucd08 \ub2a5\ub825\uc744 \ub2e4\uc9d1\ub2c8\ub2e4.\\n    \\n- **A/B \ud14c\uc2a4\ud2b8 \ubc0f \uc2e4\ud5d8 \uc124\uacc4 \ub2a5\ub825 \uc2b5\ub4dd**\\n    \\n    \uc2e4\ubb34\uc5d0\uc11c \uc790\uc8fc \uc0ac\uc6a9\ud558\ub294 \uc2e4\ud5d8 \uc124\uacc4\uc640 \uacb0\uacfc \ud574\uc11d \ub2a5\ub825\uc744 \ud559\uc2b5\ud569\ub2c8\ub2e4.\\n    \\n- **\ub9ac\ud150\uc158 \ubd84\uc11d \ubc0f \uc0ac\uc6a9\uc790 \ud589\ub3d9 \uc774\ud574**\\n    \\n    \uc0ac\uc6a9\uc790 \uc774\ud0c8/\uc794\uc874 \ubd84\uc11d\uc744 \ud1b5\ud574 \uc11c\ube44\uc2a4 \uac1c\uc120\uc758 \uc778\uc0ac\uc774\ud2b8\ub97c \ub3c4\ucd9c\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n    \\n\\n---\\n\\n## **\ud83d\udcda \ucee4\ub9ac\ud058\ub7fc \uc548\ub0b4**\\n\\n### **1. Python \uae30\ucd08 \ud559\uc2b5**\\n\\n- \ud30c\uc774\uc36c \ubb38\ubc95\uc758 \uae30\ucd08 \uc774\ud574\\n- \ubcc0\uc218\uc640 \uc790\ub8cc\ud615, \uc870\uac74\ubb38/\ubc18\ubcf5\ubb38 \ub4f1 \uae30\ubcf8 \uad6c\uc870 \uc2b5\ub4dd\\n- \uac04\ub2e8\ud55c \ub370\uc774\ud130 \ucc98\ub9ac \uc2e4\uc2b5\\n\\n### **2. SQL \uae30\ubcf8 \ucffc\ub9ac \uc791\uc131**\\n\\n- SELECT, FROM, WHERE \uad6c\ubb38 \uc774\ud574\\n- \uc870\uac74 \uae30\ubc18 \ub370\uc774\ud130 \ucd94\ucd9c \uc2e4\uc2b5\\n\\n### **3. Python \ubb38\ubc95 \uc2ec\ud654**\\n\\n- \ud568\uc218 \uc815\uc758 \ubc0f \ud65c\uc6a9\\n- \ub9ac\uc2a4\ud2b8, \ub515\uc154\ub108\ub9ac \ub4f1 \uc790\ub8cc\uad6c\uc870 \uc751\uc6a9\\n\\n### **4. SQL \uadf8\ub8f9 \uc5f0\uc0b0**\\n\\n- GROUP BY, HAVING, SUM, COUNT \ub4f1 \uc9d1\uacc4 \ud568\uc218 \uc2e4\uc2b5\\n\\n### **5~7. Python \uc2dc\uac01\ud654 \ubc0f \uc2e4\uc804 \ubd84\uc11d**\\n\\n- matplotlib, seaborn \ub4f1\uc744 \ud65c\uc6a9\ud55c \uc2dc\uac01\ud654 \uc2e4\uc2b5\\n- \ub2e4\uc591\ud55c \uadf8\ub798\ud504 \uad6c\ud604 \ubc0f \ub370\uc774\ud130 \uc778\uc0ac\uc774\ud2b8 \ub3c4\ucd9c\\n\\n### **8. Python\uc744 \ud65c\uc6a9\ud55c \ub370\uc774\ud130 \uc804\ucc98\ub9ac**\\n\\n- \ubb38\uc790\uc5f4, \uacb0\uce21\uce58 \ucc98\ub9ac\\n- \ub370\uc774\ud130 \uc815\uc81c \uae30\ubc95 \uc2e4\uc2b5\\n\\n### **9. SQL JOIN & UNNEST**\\n\\n- \ub2e4\uc591\ud55c JOIN \ubc29\uc2dd \ud559\uc2b5\\n- \ubc30\uc5f4 \ubc0f \uad6c\uc870\ud654 \ub370\uc774\ud130 \ucc98\ub9ac\\n\\n### **10. Python \uc608\uc678 \ucc98\ub9ac**\\n\\n- \uc5d0\ub7ec\uc758 \uc774\ud574 \ubc0f \ub514\ubc84\uae45\\n- \uc2e4\ubb34\uc5d0\uc11c \ud544\uc694\ud55c \uc548\uc804\ud55c \ucf54\ub4dc \uc791\uc131\\n\\n### **11. SQL \uc708\ub3c4\uc6b0 \ud568\uc218**\\n\\n- RANK, ROW_NUMBER, LAG \ub4f1 \uc708\ub3c4\uc6b0 \ud568\uc218 \uc774\ud574\\n- \uace0\uae09 \ub370\uc774\ud130 \uc9d1\uacc4\uc640 \ube44\uad50 \ubd84\uc11d\\n\\n---\\n\\n## **\ud83e\uddea \uc2e4\uc804 \ubd84\uc11d \uc2a4\ud0ac**\\n\\n### **12~13. A/B Test \ubd84\uc11d \uc2e4\uc2b5**\\n\\n- A/B \ud14c\uc2a4\ud2b8 \uad6c\uc870 \uc774\ud574\\n- \uc720\uc758\uc131 \uac80\uc815 \ubc0f \ud1b5\uacc4\uc801 \ubd84\uc11d\\n- \ud14c\uc2a4\ud2b8 \uacb0\uacfc \ud574\uc11d \ubc0f \uc2dc\uac01\ud654\\n\\n### **14. \ub9ac\ud150\uc158 \ubd84\uc11d**\\n\\n- Cohort \ubd84\uc11d \uac1c\ub150 \ud559\uc2b5\\n- \uc794\uc874\uc728 \ubc0f \uc774\ud0c8\ub960 \ubd84\uc11d\\n- SQL \uae30\ubc18 \ub9ac\ud150\uc158 \ubd84\uc11d \uc2e4\uc2b5\\n\\n---\\n\\n## **\ud83d\ude80 \ud2b8\ub799 \uc218\ub8cc \ud6c4 \uc5ec\ub7ec\ubd84\uc774 \uc5bb\uac8c \ub420 \uac83**\\n\\n- **\uc2e4\ubb34 \uc218\uc900\uc758 \ub370\uc774\ud130 \ubd84\uc11d \ud504\ub85c\uc81d\ud2b8\ub97c \uc9c1\uc811 \uc218\ud589\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.**\\n- **Python\uacfc SQL\uc744 \ud65c\uc6a9\ud574 \uc2a4\uc2a4\ub85c \ub370\uc774\ud130 \uc778\uc0ac\uc774\ud2b8\ub97c \ub3c4\ucd9c\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.**\\n- **A/B \ud14c\uc2a4\ud2b8\uc640 \ub9ac\ud150\uc158 \ubd84\uc11d \ub4f1 \uc11c\ube44\uc2a4 \uc131\uacfc \ubd84\uc11d \uc5c5\ubb34\uc5d0 \ubc14\ub85c \ud22c\uc785\ub420 \uc218 \uc788\uc2b5\ub2c8\ub2e4.**\\n\\n---\\n\\n## **\ub9c8\ubb34\ub9ac**\\n\\n\ud55c \ubc88 \ub4e4\uc5b4\uc628 \uc774\uc0c1 \uc2dc\uac04\uc744 \ub9ce\uc774 \uc4f0\uac8c \ub418\ub294 \uac83\uc740 \ub2f9\uc5f0\ud55c \uc77c\uc785\ub2c8\ub2e4.\\n\\n\ud558\uc9c0\ub9cc \ud5e4\ub9e8 \ub9cc\ud07c \ub0b4 \ub545\uc774\uace0 \ub0b4 \uae38\uc774 \ub420 \uac81\ub2c8\ub2e4."}]}')}}]);